import React, { useState } from "react";
import { motion } from "framer-motion";
import { addFood } from "../services/api";
import { Leaf, Clock, MapPin, Scale, ChevronRight } from "lucide-react";

function AddFoodPage() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [type, setType] = useState("Prepared Meal");
  const [expiry, setExpiry] = useState("");
  const [location, setLocation] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [message, setMessage] = useState(null);
  const [error, setError] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
    setIsLoading(true);
    setError(null);
    setMessage(null);
    try {
      await addFood({ title, description, quantity, type, expiry, location, image_url: imageUrl });
      setMessage("Food item listed successfully. Thank you for your contribution!");
      setTitle("");
      setDescription("");
      setQuantity(1);
      setExpiry("");
      setLocation("");
      setImageUrl("");
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50/30 py-12">
      <div className="max-w-4xl mx-auto px-6 lg:px-8">
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-12 text-center"
        >
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-emerald-100 text-emerald-700 text-sm font-black mb-6">
            <Leaf size={16} />
            <span>DONOR PORTAL</span>
          </div>
          <h2 className="text-5xl font-black text-gray-900 mb-4 tracking-tight">
            List Surplus <span className="text-primary">Food</span>
          </h2>
          <p className="text-gray-500 text-lg font-medium max-w-xl mx-auto">
            Your contribution helps reduce waste and feeds those in need. Fill in the details below to list your surplus items.
          </p>
        </motion.div>

        <motion.div 
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.1 }}
          className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-gray-100 shadow-2xl shadow-emerald-900/5"
        >
          {message && (
            <motion.div 
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className="p-4 mb-8 bg-emerald-50 border border-emerald-100 rounded-2xl text-emerald-700 text-sm font-bold flex items-center gap-3"
            >
              <div className="w-8 h-8 bg-emerald-500 rounded-full flex items-center justify-center text-white font-black">✓</div>
              {message}
            </motion.div>
          )}
          {error && (
            <motion.div 
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className="p-4 mb-8 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-sm font-bold flex items-center gap-3"
            >
              <div className="w-8 h-8 bg-red-500 rounded-full flex items-center justify-center text-white font-black">!</div>
              {error}
            </motion.div>
          )}
          
          <form onSubmit={handleSubmit} className="space-y-10">
            <div className="form-group">
              <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                <Leaf size={14} className="text-primary" />
                Food Title
              </label>
              <input 
                value={title} 
                onChange={(e) => setTitle(e.target.value)} 
                required 
                className="w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold placeholder:text-gray-300 focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none"
                placeholder="e.g. Leftover Biryani (Serves 20)"
              />
            </div>

            <div className="form-group">
              <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                Description & Packaging
              </label>
              <textarea 
                value={description} 
                onChange={(e) => setDescription(e.target.value)} 
                rows="4" 
                required 
                className="w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold placeholder:text-gray-300 focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none"
                placeholder="Describe the food condition, packaging (boxes/containers), and any allergens..."
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="form-group">
                <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                  <Scale size={14} className="text-primary" />
                  Quantity (Servings)
                </label>
                <input 
                  value={quantity} 
                  onChange={(e) => setQuantity(Number(e.target.value))} 
                  type="number" 
                  min="1" 
                  required 
                  className="w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none"
                />
              </div>
              <div className="form-group">
                <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                  Food Category
                </label>
                <select 
                  value={type} 
                  onChange={(e) => setType(e.target.value)} 
                  required 
                  className="w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none appearance-none"
                >
                  <option value="Prepared Meal">Prepared Meal</option>
                  <option value="Bakery & Sweets">Bakery & Sweets</option>
                  <option value="Vegetables & Fruits">Vegetables & Fruits</option>
                  <option value="Grains & Dry Goods">Grains & Dry Goods</option>
                  <option value="Dairy Products">Dairy Products</option>
                </select>
              </div>
            </div>

            <div className="form-group">
              <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                Food Image URL
              </label>
              <div className="flex flex-col md:flex-row gap-6 items-start">
                <input 
                  value={imageUrl} 
                  onChange={(e) => setImageUrl(e.target.value)} 
                  className="flex-1 w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold placeholder:text-gray-300 focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none"
                  placeholder="https://images.unsplash.com/photo-..."
                />
                {imageUrl && (
                  <div className="w-full md:w-32 h-20 rounded-xl overflow-hidden border border-gray-100 flex-shrink-0">
                    <img src={imageUrl} alt="Preview" className="w-full h-full object-cover" />
                  </div>
                )}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="form-group">
                <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                  <Clock size={14} className="text-primary" />
                  Best Before
                </label>
                <input 
                  value={expiry} 
                  onChange={(e) => setExpiry(e.target.value)} 
                  type="datetime-local" 
                  required 
                  className="w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none"
                />
              </div>
              <div className="form-group">
                <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest ml-1 mb-3 block">
                  <MapPin size={14} className="text-primary" />
                  Pickup Point
                </label>
                <input 
                  value={location} 
                  onChange={(e) => setLocation(e.target.value)} 
                  required 
                  className="w-full bg-emerald-50/50 border-2 border-transparent rounded-2xl py-5 px-8 text-gray-900 font-semibold placeholder:text-gray-300 focus:bg-white focus:border-primary/20 focus:ring-0 transition-all outline-none"
                  placeholder="Main Entrance / Reception"
                />
              </div>
            </div>

            <motion.button 
              type="submit"
              disabled={isLoading}
              whileHover={{ scale: 1.01 }}
              whileTap={{ scale: 0.99 }}
              className={`w-full bg-primary text-white py-6 rounded-[2rem] font-black text-xl flex items-center justify-center gap-3 shadow-2xl shadow-primary/30 transition-all ${isLoading ? 'opacity-70 cursor-not-allowed' : 'hover:bg-primary-hover'}`}
            >
              {isLoading ? "Publishing..." : "Post Listing Now"}
              {!isLoading && <ChevronRight size={24} />}
            </motion.button>
          </form>
        </motion.div>
      </div>
    </div>
  );
}

export default AddFoodPage;
